# Prototypes
sub prototype_sub ($$) {
    my ($a, $b) = @_;
    return $a + $b;
}

sub arrayref_proto (\@) {
    my $arrayref = shift;
    return @$arrayref;
}

sub optional_proto ($;$) {
    my ($required, $optional) = @_;
    return defined $optional ? $required + $optional : $required;
}

